import json
import boto3
import os
from botocore.exceptions import ClientError

sns_client = boto3.client('sns')

ALLOWED_TOPIC_ARNS = os.environ.get('ALLOWED_TOPIC_ARNS', '').split(',')
ALLOWED_TOPIC_ARNS = [arn.strip() for arn in ALLOWED_TOPIC_ARNS if arn.strip()]

def validate_topic_arn(topic_arn):
    """Validate that the topic ARN is in the allowed list"""
    if not ALLOWED_TOPIC_ARNS:
        raise ValueError("No allowed topic ARNs configured")
    
    if topic_arn not in ALLOWED_TOPIC_ARNS:
        raise ValueError(f"Topic ARN {topic_arn} is not in the allowed list")
    
    return True

def validate_topic_policy(topic_arn):
    """Validate that the SNS topic has proper access controls"""
    try:
        response = sns_client.get_topic_attributes(TopicArn=topic_arn)
        policy = json.loads(response['Attributes'].get('Policy', '{}'))
        
        if not policy or 'Statement' not in policy:
            return True
        
        for statement in policy['Statement']:
            principal = statement.get('Principal', {})
            
            # Check for overly permissive principals
            if principal == '*' or principal.get('AWS') == '*':
                effect = statement.get('Effect', '')
                action = statement.get('Action', [])
                
                if effect == 'Allow':
                    # Check if there's a condition that restricts access
                    if 'Condition' not in statement:
                        raise ValueError(
                            f"Topic {topic_arn} has an open subscription policy. "
                            "Public access without conditions is not allowed."
                        )
        
        return True
    except ClientError as e:
        raise ValueError(f"Unable to validate topic policy: {str(e)}")

def publish_standard_message(topic_arn, message, subject=None, message_attributes=None):
    """Publish a standard text message to SNS topic"""
    validate_topic_arn(topic_arn)
    validate_topic_policy(topic_arn)
    
    params = {
        'TopicArn': topic_arn,
        'Message': message
    }
    
    if subject:
        params['Subject'] = subject
    
    if message_attributes:
        params['MessageAttributes'] = message_attributes
    
    response = sns_client.publish(**params)
    return response['MessageId']

def publish_structured_message(topic_arn, message_dict, subject=None):
    """Publish a structured message with different formats for different protocols"""
    validate_topic_arn(topic_arn)
    validate_topic_policy(topic_arn)
    
    message_structure = {
        'default': message_dict.get('default', json.dumps(message_dict)),
        'email': message_dict.get('email', message_dict.get('default', '')),
        'sms': message_dict.get('sms', message_dict.get('default', ''))[:140],
        'sqs': json.dumps(message_dict.get('sqs', message_dict)),
        'lambda': json.dumps(message_dict.get('lambda', message_dict))
    }
    
    params = {
        'TopicArn': topic_arn,
        'Message': json.dumps(message_structure),
        'MessageStructure': 'json'
    }
    
    if subject:
        params['Subject'] = subject
    
    response = sns_client.publish(**params)
    return response['MessageId']

def publish_with_attributes(topic_arn, message, attributes, subject=None):
    """Publish message with custom message attributes for filtering"""
    validate_topic_arn(topic_arn)
    validate_topic_policy(topic_arn)
    
    message_attributes = {}
    for key, value in attributes.items():
        if isinstance(value, str):
            message_attributes[key] = {
                'DataType': 'String',
                'StringValue': value
            }
        elif isinstance(value, (int, float)):
            message_attributes[key] = {
                'DataType': 'Number',
                'StringValue': str(value)
            }
        elif isinstance(value, list):
            message_attributes[key] = {
                'DataType': 'String.Array',
                'StringValue': json.dumps(value)
            }
    
    params = {
        'TopicArn': topic_arn,
        'Message': message,
        'MessageAttributes': message_attributes
    }
    
    if subject:
        params['Subject'] = subject
    
    response = sns_client.publish(**params)
    return response['MessageId']

def lambda_handler(event, context):
    """
    Lambda handler for publishing messages to SNS topics
    
    Expected event structure:
    {
        "topic_arn": "arn:aws:sns:region:account:topic-name",
        "notification_type": "standard|structured|attributed",
        "message": "message content or dict",
        "subject": "optional subject",
        "attributes": {"key": "value"} (for attributed type)
    }
    """
    try:
        topic_arn = event.get('topic_arn')
        notification_type = event.get('notification_type', 'standard')
        message = event.get('message')
        subject = event.get('subject')
        
        if not topic_arn:
            return {
                'statusCode': 400,
                'body': json.dumps({'error': 'topic_arn is required'})
            }
        
        if not message:
            return {
                'statusCode': 400,
                'body': json.dumps({'error': 'message is required'})
            }
        
        message_id = None
        
        if notification_type == 'standard':
            message_text = message if isinstance(message, str) else json.dumps(message)
            message_id = publish_standard_message(topic_arn, message_text, subject)
            
        elif notification_type == 'structured':
            message_dict = message if isinstance(message, dict) else {'default': str(message)}
            message_id = publish_structured_message(topic_arn, message_dict, subject)
            
        elif notification_type == 'attributed':
            attributes = event.get('attributes', {})
            message_text = message if isinstance(message, str) else json.dumps(message)
            message_id = publish_with_attributes(topic_arn, message_text, attributes, subject)
            
        else:
            return {
                'statusCode': 400,
                'body': json.dumps({
                    'error': f'Invalid notification_type: {notification_type}. '
                             'Must be one of: standard, structured, attributed'
                })
            }
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Message published successfully',
                'messageId': message_id,
                'topicArn': topic_arn
            })
        }
        
    except ValueError as e:
        return {
            'statusCode': 403,
            'body': json.dumps({'error': str(e)})
        }
    except ClientError as e:
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': 'Failed to publish message',
                'details': str(e)
            })
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': 'Internal server error',
                'details': str(e)
            })
        }